const text = items[0].json.output;

// 1. 判定類別
let category = "聊天模式";
if (text.includes("類別：體重更新")) {
    category = "體重更新";
} else if (text.includes("類別：聊天模式")) {
    category = "聊天模式";
}

// 2. 初始化變數
let weight = null;
let comment = "";

// 3. 處理抓取邏輯
if (category === "體重更新") {
    const dataLineMatch = text.match(/\[數據\]：體重\s*(\d+(\.\d+)?)/);
    weight = dataLineMatch ? parseFloat(dataLineMatch[1]) : null;

    // 體重更新時，教練不廢話
    comment = ""; 
} else {
    // 【關鍵優化】：如果是聊天模式，直接保留 Agent 輸出的所有內容
    // 不要再用 Regex 去切標籤，因為 Agent 可能會說出很長一段包含數據的分析
    comment = text.replace(/^類別：聊天模式[。，]?\s*/, "").trim();
}

return [{
  json: {
    category: category,
    weight: weight,
    comment: comment,
    full_text: text 
  }
}];

