// 1. 取得所有歷史紀錄
const historyLogs = $input.all();

// 2. 取得今日體重
const todayWeight = parseFloat($node["解析文字：類別分流處理"].json.weight);

// 3. 在 JS 裡進行排序（確保日期由新到舊，處理 Google Sheets 排序不穩定的問題）
let sortedHistory = historyLogs.sort((a, b) => {
    return new Date(b.json['日期']) - new Date(a.json['日期']);
});

// 4. 提取歷史體重數值並過濾掉無效資料
let weightArray = sortedHistory.map(item => parseFloat(item.json['體重'])).filter(w => !isNaN(w));

// 5. 取最近 7 筆數據（今日體重 + 歷史前 6 筆）
let last7Days = [todayWeight, ...weightArray].slice(0, 7);

// 6. 計算 7 天平均值
let sum = last7Days.reduce((a, b) => a + b, 0);
let avg7Days = sum / last7Days.length;

// 7. 計算趨勢 (使用當前體重與平均值的差值)
let trend = "穩定";
let diff_avg = todayWeight - avg7Days; 

if (diff_avg > 0.3) {
    trend = "上升";
} else if (diff_avg < -0.3) {
    trend = "下降";
} else {
    trend = "穩定";
}

// === 🚀 新增：QuickChart 趨勢圖生成邏輯 ===
// 圖表需要「由舊到新」排列，所以反轉數組
const chartData = [...last7Days].reverse();
const chartLabels = chartData.map((_, i) => i + 1); // 標籤為 1, 2, 3...

// 設置圖表樣式
const chartConfig = {
  type: 'line',
  data: {
    labels: chartLabels,
    datasets: [{
      label: '體重 (kg)',
      data: chartData,
      borderColor: '#FF4B4B', // 阿冰的代表色：紅色
      backgroundColor: 'rgba(255, 75, 75, 0.1)', // 填充淡紅色
      fill: true,
      pointRadius: 5,
      pointBackgroundColor: '#FF4B4B',
      lineTension: 0.3 // 讓線條圓滑一點
    }]
  },
  options: {
    title: { display: true, text: '最近 7 次體重變化趨勢' }
  }
};

// 將設定轉換為 URL 編碼
const chartUrl = `https://quickchart.io/chart?c=${encodeURIComponent(JSON.stringify(chartConfig))}`;

// 8. 輸出結構化 JSON 數據
return [{
    json: {
        today_weight: todayWeight,
        avg_7days: avg7Days.toFixed(2),
        diff_avg: diff_avg.toFixed(2),
        trend: trend,
        data_count: last7Days.length,
        chart_url: chartUrl // 這是給 LINE Flex 使用的動態圖表網址
    }
}];

// 1. 取得 AI 輸出的原始文字內容
const rawText = $input.first().json.output[0].content[0].text;

// 2. 提取數字 (今日體重 與 7天平均)
// 使用 \d+(\.\d+)? 抓取文字中出現的所有數字
const numbers = rawText.match(/\d+(\.\d+)?/g);

// 假設第一個數字是今日體重，第二個數字是平均值
const todayWeight = (numbers && numbers.length >= 1) ? parseFloat(numbers[0]) : null;
const avg7Days = (numbers && numbers.length >= 2) ? parseFloat(numbers[1]) : null;

// 3. 提取評論內容
// 因為輸出已經很精簡，我們直接將整段文字作為評語回傳給 LINE
const comment = rawText;

// 4. 輸出結構化 JSON 數據
return [{
    json: {
        category: "體重更新",
        today_weight: todayWeight,
        avg_7days: avg7Days,
        comment: comment,
        full_text: rawText
    }
}];

// 1. 取得 LINE 傳回的按鈕隱藏數據
const postbackData = $json.body.events[0].postback.data;

// 2. 手動解析 Query String
const result = {};
const pairs = postbackData.split('&');

for (const pair of pairs) {
    const [key, value] = pair.split('=');
    result[key] = decodeURIComponent(value || "");
}

// 3. 【關鍵修正】對齊 Flex Message 按鈕埋入的欄位名稱
// 當 action=ignore 時，按鈕埋的是 orig_cal, orig_prot 等
return {
    action: result.action,
    food_name: result.food,
    // 這裡使用邏輯運算符：如果 result.cal 有值就用它(確認紀錄分支)，不然就用 result.orig_cal(數值不對分支)
    cal: parseInt(result.cal || result.orig_cal) || 0,
    protein: parseFloat(result.prot || result.orig_prot) || 0,
    carb: parseFloat(result.carb || result.orig_carb) || 0,
    fat: parseFloat(result.fat || result.orig_fat) || 0,
    sugar: parseFloat(result.sugar || result.orig_sugar) || 0,
    replyToken: $json.body.events[0].replyToken,
    userId: $json.body.events[0].source.userId
};

