// 1. 取得用戶輸入與暫存比例
const webhookData = $("Webhook").first().json;
const userText = webhookData.body.events[0].message.text;
const newCal = parseInt(userText.match(/\d+/)[0]) || 0; 
const temp = $json; // 這裡是 Get row(s) in sheet1 的暫存數據

// 2. 計算這一餐修正後的數值
const ratio = newCal / (parseFloat(temp['原始熱量']) || 1);
const current = {
  food_name: temp['食物名稱'] || "手動修正紀錄",
  cal: newCal,
  protein: Math.round(parseFloat(temp['原始蛋白質']) * ratio) || 0,
  carb: Math.round(parseFloat(temp['原始碳水']) * ratio) || 0,
  fat: Math.round(parseFloat(temp['原始脂肪']) * ratio) || 0,
  sugar: Math.round(parseFloat(temp['原始糖分']) * ratio) || 0
};

// 3. 獲取今日「其他餐」的累計 (關鍵：指向新增加的節點)
let totalPast = { cal: 0, prot: 0, fat: 0, carb: 0, sugar: 0 };
try {
    // 這裡請確認節點名稱是否與你剛新增的「讀取今日正式紀錄_修正路徑」一致
    const pastRecords = $("讀取今日正式紀錄_修正路徑").all(); 
    pastRecords.forEach(item => {
        const row = item.json;
        if (row['食物名稱']) {
            totalPast.cal += parseFloat(row['估算熱量(kcal)']) || 0;
            totalPast.prot += parseFloat(row['蛋白質(g)']) || 0;
            totalPast.fat += parseFloat(row['脂肪(g)']) || 0;
            totalPast.carb += parseFloat(row['碳水(g)']) || 0;
            totalPast.sugar += parseFloat(row['糖(g)']) || 0;
        }
    });
} catch (e) {}

// 4. 輸出扁平化數據給 Flex Message
return [{
  json: {
    food_name: current.food_name,
    cal: current.cal,
    protein: current.protein,
    fat: current.fat,
    carb: current.carb,
    sugar: current.sugar,
    // 累加：歷史 + 當前修正
    cumulative_cal: Math.round(totalPast.cal + current.cal),
    cumulative_prot: (totalPast.prot + current.protein).toFixed(1),
    cumulative_fat: (totalPast.fat + current.fat).toFixed(1),
    cumulative_carb: (totalPast.carb + current.carb).toFixed(1),
    cumulative_sugar: (totalPast.sugar + current.sugar).toFixed(1),
    replyToken: webhookData.body.events[0].replyToken,
    userId: webhookData.body.events[0].source.userId
  }
}];

